var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"리플레이서 각 부대 반전!","JPN":"リプレイサー各部隊が反転！","ENG":"All Replacer units have been routed!","TWN":"克隆集團各部隊調頭！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"퇴각합니다!","JPN":"退却しています！","ENG":"They’re retreating!","TWN":"並且撤退了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......추, 추적할까요?","JPN":"……つ、追跡しましょうか？","ENG":"S-should we pursue them?","TWN":"……要、要追擊嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......무슨 말도 안 되는 소릴.","JPN":"……バカ言うな。","ENG":"Don't be ridiculous.","TWN":"……說什麼傻話。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다음 명령까지 현 위치에서 재정비. 추적은 없다.","JPN":"次の命令まで現在の位置で再整備。追跡は無しで。","ENG":"Standby and regroup until further instructions. We won’t be pursuing them.","TWN":"在下一個命令下達前原地整頓，不進行追擊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아, 알겠습니다.","JPN":"りょ、了解しました。","ENG":"U-understood.","TWN":"是，知道了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"헉...... 헉......","JPN":"はあ……はあ……","ENG":"Huff... Huff...","TWN":"哈……哈……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 괜찮으세요?","JPN":"ミナさん、大丈夫ですか？","ENG":"You okay, Mina?","TWN":"米娜小姐，妳還好嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"괜찮...... 지 않네, 젠장.","JPN":"大丈夫……じゃないな、ちくしょう。","ENG":"No... Not okay. Crap.","TWN":"很好……才怪。可惡。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"힘들어 죽을 것 같아......","JPN":"苦しくて死にそう。","ENG":"I think I’m gonna pass out...","TWN":"快累死了……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그렇게 말씀하시는 걸 보니 괜찮으신 것 같네요.","JPN":"ハハ、そう言ってる間は大丈夫そうですね。","ENG":"Haha, sounds like you're doing just fine.","TWN":"哈哈，還能抱怨就代表妳沒事喔。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"일단 함선으로 돌아가서 조금이라도 쉬고 계세요.","JPN":"一旦艦船に戻って少しでも休んでください。","ENG":"Why don’t you go get some rest at the ship for now?","TWN":"先回到艦船上稍微休息一下吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"남은 시간이 얼마 없을 것 같으니까요.","JPN":"残り時間があまりないと思うので。","ENG":"I don’t think there’s much time left anyway.","TWN":"剩下的時間也不多了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......그쪽은 어떻지?","JPN":"……そっちはどうだ？","ENG":"How’s everything over there?","TWN":"……那邊怎麼樣了？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"알면서 뭘 물어? 별로야.","JPN":"知ってて聞く？　イマイチだよ。","ENG":"Why bother asking? You know. Kinda sucks.","TWN":"妳是明知故問嗎？當然不怎麼樣。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"시간이 충분한 상태에서 싸운다면 이쪽이 유리하겠지만......","JPN":"十分な時間がある状態で戦えば、こっちが有利だろうけど……","ENG":"We’d have the advantage if we had plenty of time to fight...","TWN":"如果是在時間充裕的狀態下戰鬥，我們應該是有優勢的……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......지금 가장 부족한 것도 바로 시간이지.","JPN":"……今最も足りないのは、時間だからな。","ENG":"But time’s not on our side either.","TWN":"……但是現在最缺的正是時間。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 그 서윤이라는 친구, 영리하게 싸우는 방법을 잘 알고 있어.","JPN":"そうだ。あのシズカという人、賢い戦い方を熟知してるのね。","ENG":"That's right. That Seo Yoon girl knows how to fight smart.","TWN":"是啊。那個叫徐芸的朋友，非常清楚什麼是聰明的戰鬥方法。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이래서야 불리함을 인정할 수밖에 없겠는걸.","JPN":"これじゃ、こっちの劣勢を認めるしかないよ。","ENG":"At this rate, I guess we have to admit we’re at a disadvantage.","TWN":"這樣我們只能承認現在的局勢對我們很不利。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"보급에 여유는 있나?","JPN":"補給に余裕はあるのか？","ENG":"Got enough supplies?","TWN":"我們的補給充足嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그럴 리가 있겠어? 저길 봐......","JPN":"そんなわけないでしょ、あっちを見て……","ENG":"What do you think? Look over there...","TWN":"怎麼可能？妳看那裡……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......그쪽의 보급계 담당은 누굽니까?","JPN":"……そっちの補給係は誰です？","ENG":"Who’s the quartermaster over there?","TWN":"……這邊是誰負責補給的？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"탄약과 이터니움 에너지 팩이 남아 있다면 지원을 받고 싶습니다만.","JPN":"弾薬とエタニウムエネルギーパックの余分があるなら、支援を受けたいのですが。","ENG":"We’d appreciate any surplus ammunition and Eternium energy packs you may be able to supply.","TWN":"彈藥和永恆之金能量包還有剩的話，希望可以支援我們……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그, 그게...... 저희 쪽도 물자가 바닥나서요......","JPN":"その、それが……私どもも物資が底をついてしまいまして……","ENG":"W-well... We're out of supplies as well, you see...","TWN":"這、這個……我們的物資也不夠了……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"돈 문제라면 걱정하지 않으셔도 됩니다.","JPN":"お金の問題なら心配無用ですよ。","ENG":"If it's a matter of money, you don’t need to worry.","TWN":"不用擔心錢的問題。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실전 상황이니만큼 원한다면 시세의 세 배,","JPN":"実戦中なので、望むなら相場の3倍、","ENG":"As we’re in combat, we're willing to offer you three times the market price.","TWN":"因為是實戰狀況，你們願意的話，我們以市價的三倍……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아니, 그 이상의 값으로 구매하도록 하겠습니다.","JPN":"いや、それ以上の値段で引き取ります。","ENG":"Actually, more than that.","TWN":"不，以市價的三倍以上購買。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"돈 문제가 아니라 진짜 아무것도 없다니까요?","JPN":"お金の問題ではなく、本当に何もないんですよ。","ENG":"Seriously, it’s not because of money. We're really out too!","TWN":"不是錢的問題，是我們真的什麼都沒有了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"직접 보세요.","JPN":"ほら、見てみてください。","ENG":"Have a look yourself.","TWN":"您直接看吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"에너지 잔량도 간신히 이터니움 드라이브를 기동할 정도뿐이고......","JPN":"エネルギー残量も、辛うじてエタニウムドライブを起動する程で……","ENG":"We barely have enough energy to keep the Eternium Drive going...","TWN":"剩餘的能量只夠啟動永恆之金引擎。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"이대로 한 번 더 전투를 하게 되면 현실 부상도 불가능할 정도에요.","JPN":"このままでもう一度戦闘したら、現実世界への浮上もできなくなるくらいです。","ENG":"If we have another battle, we might not even be able to return to our dimension.","TWN":"照這種情況，只要在戰鬥一次的話，連躍出到現世的能量都不夠了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"후우...... 거짓말은 아닌 것 같군요.","JPN":"ふう……嘘ではなさそうですね。","ENG":"Alas... It appears you were speaking the truth.","TWN":"呼……好像不是謊話呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"了解いたしました。","ENG":"Understood.","TWN":"我知道了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"죄, 죄송합니다.","JPN":"も、申し訳ありません。","ENG":"S-sorry.","TWN":"抱、抱歉。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"무슨 태스크포스가 그래?","JPN":"これでもタスクフォースカンパニーなの？","ENG":"What kind of a TASKFORCE are you?","TWN":"這算哪門子的特遣勢力啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"산만 한 배를 몰고 다니면서 그 정도 보급품도 안 가지고 다녀?","JPN":"こんなにでっかい船を乗り回しながら、その程度の補給品すら持ってないわけ？","ENG":"You fly around a huge ship like that and you don’t even carry enough supplies with you?","TWN":"開著一艘破船，然後連足夠的補給品都沒帶嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"당신이 그런 소리 하면 안 되지!!","JPN":"あんたにそんなこと言われる筋合いはないわ！！","ENG":"You don't get to say that!","TWN":"妳怎麼能這麼說！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"이게 다 지난번에 당신이 비상용 창고까지 탈탈 털어서 그렇잖아요!!","JPN":"これも全部、この前あんたが非常用倉庫まですっからかんにしたからでしょうが！！","ENG":"This is all because you raided our supplies last time, including the emergency storage!","TWN":"還不都是因為妳上次把緊急倉庫都掏空了！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......진퇴양난이로군.","JPN":"……進むも地獄、退くも地獄だな。","ENG":"Looks like we're stuck in a rut here.","TWN":"……真是進退兩難啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만, 그렇다고 정말 돌아갈 수는 없겠지?","JPN":"しかし、だからって、帰るわけにはいかないよな？","ENG":"But we can’t turn back now, can we?","TWN":"但話是這麼說，我們真的沒有辦法回去嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......물론이야.","JPN":"……もちろんよ。","ENG":"Precisely.","TWN":"……當然了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"더 시간을 끌다가 리플레이서 간부들이라도 나타나면 그땐 정말 끝이니까.","JPN":"もっと時間を稼がれてリプレイサーの幹部たちでも現われたら、その時は本当におしまいだからね。","ENG":"If we stall any further, the Replacer officers will show up, and then we're really done for.","TWN":"再拖下去的話，等到克隆集團的幹部們趕來，我們就真的完了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지금은 불리하더라도 앞으로 나아가는 수밖에 없어.","JPN":"今は不利でも前に突き進むしかないわよ。","ENG":"We’d better keep moving forward even if things aren’t working in our favor right now.","TWN":"就算情況對我們不利，也只能前進了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......알겠다.","JPN":"……了解した。","ENG":"Understood.","TWN":"……知道了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"출발한다.","JPN":"出発しよう。","ENG":"We're leaving.","TWN":"出發。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다들 준비하도록.","JPN":"みんな、準備を。","ENG":"Everyone, get ready.","TWN":"大家做好準備。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"버, 벌써요? 조금 더 쉬었다가 가는 게 좋지 않을까요?","JPN":"は、早くないですか？　もう少し休んでから行った方が良いのでは？","ENG":"A-already? Shouldn’t we rest up just a little more?","TWN":"立、立刻嗎？不再休息一會嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"다들 너무 지친 것 같은데요.......","JPN":"皆さん、疲れ切っているようで……","ENG":"Everyone seems so exhausted.","TWN":"大家看起來也都很累……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"나도 그러고 싶지만, 지금은 여유가 없군.","JPN":"私もそうしたいところだが、今は何しろ余裕がない。","ENG":"I wish we could, but we just don’t have that luxury right now.","TWN":"我也想要那樣，但沒有那個時間。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"조금이라도 여력이 있을 때...... 마무리를 지어야 해.","JPN":"少しでも余力がある時に……とどめを刺さないと。","ENG":"Before we are completely out of commission... we must end this while we still can.","TWN":"趁我們還有一點餘力的時候……得把任務完成才行。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};